import React, { useState } from 'react';
import { useCalendar } from '../context/CalendarContext';

const TaskEditor = ({ task, onClose }) => {
    const { updateTask, deleteTask } = useCalendar();
    const [editedTask, setEditedTask] = useState({ ...task });

    const handleSubmit = async (e) => {
        e.preventDefault();
        e.stopPropagation();
        
        try {
            await updateTask(task.startDate, task.group_id, editedTask);
            console.log('Task updated successfully');
            onClose();
        } catch (error) {
            console.error('Failed to update task:', error);
            alert(`Failed to update task: ${error.message}`);
        }
    };

    const handleDelete = async (e) => {
        e.preventDefault();
        e.stopPropagation();
        
        if (window.confirm('Are you sure you want to delete this task?')) {
            try {
                await deleteTask(task.group_id);
                console.log('Task deleted successfully');
                onClose();
            } catch (error) {
                console.error('Failed to delete task:', error);
                alert(`Failed to delete task: ${error.message}`);
            }
        }
    };

    return (
        <form onSubmit={handleSubmit} onClick={e => e.stopPropagation()} className="task-form">
            <h3>Edit Task</h3>
            <input
                type="text"
                value={editedTask.title}
                onChange={e => setEditedTask(prev => ({ ...prev, title: e.target.value }))}
                placeholder="Task title"
                required
            />
            <textarea
                value={editedTask.description}
                onChange={e => setEditedTask(prev => ({ ...prev, description: e.target.value }))}
                placeholder="Description (optional)"
            />
            <input
                type="time"
                value={editedTask.time}
                onChange={e => setEditedTask(prev => ({ ...prev, time: e.target.value }))}
            />
            <input
                type="color"
                value={editedTask.color}
                onChange={e => setEditedTask(prev => ({ ...prev, color: e.target.value }))}
            />
            <div className="form-buttons">
                <button type="submit">Save Changes</button>
                <button type="button" onClick={handleDelete} className="delete-button">
                    Delete Task
                </button>
                <button type="button" onClick={onClose}>Cancel</button>
            </div>
        </form>
    );
};

export default TaskEditor;
